function [A,B,C,D,xName,uName,yName] = tloadlin(matfile,quiet)
%tloadlin  load linear system generated by dymosim into Matlab work space
%          The linear system is described by
%              der(x) = A*x + B*u
%                  y  = C*x + D*u
%
%          [A,B,C,D]=tloadlin;       loads linear system from mat-file 'dslin.mat'.
%          [A,B,C,D]=tloadlin(file); loads linear system from mat-file '<file>.mat'.
%
%         where,
%            A,B,C,D: matrices of linear system
%            xName  : names of states  x
%            uName  : names of inputs  u
%            yName  : names of outputs y
%
%See also: traj.

%    Copyright (c) 1995,1996,1997 by DLR.
%    Copyright (C) 1997-2001 Dynasim AB.
%    All rights reserved.

% it is expected that four matrices are on file:
%    Aclass (contains class-name), nx, xuyName, ABCD.

if nargin<2
  quiet=0;
end
% determine file name
  if nargin < 1
     file = 'dslin.mat';
  else
     matfile = lower(matfile);
     ii = findstr(matfile,'.mat');
     if isempty(ii)
        file = [matfile,'.mat'];
     elseif strcmp(matfile(1,ii:size(matfile,2)),'.mat')
        file = matfile;
     else
        error( ['filename (= "',matfile,'") has not extension ".mat"'] )
     end
  end

% check file existence
   if exist( file ) ~= 2
      error( sprintf( ['"', file, '" does not exist in directory\n   %s'], pwd ) )
   end

% load data
  eval( [ 'load ' file ] );

% check whether file contains correct variable names
  if exist('Aclass') ~= 1
     error( ['no linear system on file "' file '" (matrix "Aclass" is missing).'] )
  elseif exist('nx') ~= 1
     error( ['no linear system on file "' file '" (matrix "nx" is missing).'] )
  elseif exist('xuyName') ~= 1
     error( ['no linear system on file "' file '" (matrix "xuyName" is missing).'] )
  elseif exist('ABCD') ~= 1
     error( ['no linear system on file "' file '" (matrix "ABCD" is missing).'] )
  end

% check whether file has correct class name
  classReq = 'AlinearSystem';
  ncol = min( size(classReq,2), size(Aclass,2) );
  nrow = size(Aclass,1);
  if nrow < 1 or (Aclass(1,1:ncol) ~= classReq(1,1:ncol))
     error( [ 'file "' file '" is not of class ' classReq ] )
  end

% check whether matrices have compatible dimensions
  dimx        = nx(1);
  dimName     = size(xuyName,1);
  [dim1,dim2] = size(ABCD);
  if dimx > dim1 | dimx > dim2
     error( ['nx > row/column number of matrix ABCD on file "' file '"'] )
  end
  dimu = dim2 - dimx;
  dimy = dim1 - dimx;
  dimc = size(xuyName,2);

% copy data in output arguments
  if dimx > 0
     A = ABCD(1:dimx,1:dimx);
     if dimu > 0
        B = ABCD(1:dimx,dimx+1:dim2);
     else
        B = [];
     end
     if dimy > 0
        C = ABCD(dimx+1:dim1,1:dimx);
     else
        C = [];
     end
  else
     A = [];
     B = [];
     C = [];
  end
  if dimu > 0  &  dimy > 0
     D = ABCD(dimx+1:dim1,dimx+1:dim2);
  else
     D = [];
  end

  if dimx > 0 
     xName = tnblank( xuyName(1:dimx,1:dimc) );
  else
     xName = [];
  end

  if dimu > 0
     uName = tnblank( xuyName(dimx+1:dimx+dimu,1:dimc) );
  else
     uName = [];
  end

  if dimy > 0
     yName = tnblank( xuyName(dimx+dimu+1:dimx+dimu+dimy,1:dimc) );
  else
     yName = [];
  end

if ~quiet
% print info message
  if file(1,1) == '/' | file(1,1) == '\' | file(1,2) == ':'
     disp( [ '> ', file, ' loaded.' ] )
  else
     machine = computer;
     if machine(1,1:2) == 'PC'
        disp( [ '> ', lower(pwd), '\', lower(file), ' loaded.' ] )
     else
        disp( [ '> ', pwd, '/', file, ' loaded.' ] )
     end
  end
end
